from vex import VexClient
from google_adk import Coordinator

vex = VexClient(api_key="your-vex-key")

@vex.guard("brand_consistency")
def check_brand_voice(content):
    return (
        'professional' in content.lower() or 
        'expert' in content.lower() and
        len(content.split()) > 200
    )

@vex.guard("factual_accuracy")
def verify_facts(content):
    facts = [s for s in content.split() if s.startswith('Fact:')]
    return len(facts) >= 3

# Apply to coordinator
coordinator = Coordinator(
    agents=[brand_agent, research_agent],
    before_agent_callback=vex.multi_guard([
        check_brand_voice,
        verify_facts
    ])
)

result = coordinator.run("Generate marketing content")

from vex import VexClient

vex = VexClient(api_key="your-key")

@vex.guard("no_circular_deps")
def detect_loops(session_state):
    agent_history = session_state.get('agent_calls', [])
    recent_agents = agent_history[-5:]
    return len(set(recent_agents)) > 2  # Not looping same 2 agents

@vex.guard("session_integrity")
def validate_state(session):
    return (
        len(session['context']) < 10000 and  # Prevent token bloat
        'facts_verified' in session  # Required state present
    )

coordinator = Coordinator(
    before_agent_callback=vex.multi_guard([
        detect_loops,
        validate_state
    ]),
    max_iterations=10
)
